Name: csv_export
Purpose: Convert tabular data (headers + rows) into RFC 4180–compliant CSV with consistent columns and proper escaping.
Inputs: headers: string[], rows: (string|number)[][]
Output: string (CSV)

Implementation (csv_export.js):
function csv_export(headers, rows) {
  const escape = (v) => {
    if (v === null || v === undefined) return '';
    const s = String(v);
    if (/[",\n]/.test(s)) return '"' + s.replace(/"/g, '""') + '"';
    return s;
  };
  const all = [headers, ...rows];
  return all.map(r => r.map(escape).join(',')).join('\n');
}
module.exports = csv_export;
